UPDATE project_modules SET data = '{"deliverables":[{"icon":"💻","label":"GitHub 소스코드 (Private Repo)"},{"icon":"🌐","label":"배포된 운영/스테이징 URL"},{"icon":"📘","label":"API 명세서 (Swagger / OpenAPI)"},{"icon":"📊","label":"ERD 및 시스템 아키텍처 다이어그램"},{"icon":"📖","label":"운영 매뉴얼 + 관리자 가이드"},{"icon":"🎬","label":"기능 시연 영상"}],"formats":["GitHub URL","Swagger JSON","PDF",".drawio / .png","MP4"],"delivery":["GitHub Private Repo Invite","DevBridge 채팅 첨부","최종 산출물 ZIP 별도 전달"],"notes":["주요 기술 스택: PyTorch 2.x, Vue 3 + Pinia, Apache Kafka, Node.js 20","운영 환경 배포는 클라이언트 승인 후 진행"]}' WHERE project_id = 1188 AND module_key = 'deliverable';
