UPDATE project_modules SET data = '{"included":["SNS 광고 분석 SaaS #036 핵심 기능 설계 및 구현","EKS / GKE, Swift (iOS Native) 기반 백엔드/프론트 개발","프롭테크 도메인 비즈니스 로직 구현","REST API 또는 GraphQL 인터페이스 제공","유닛 테스트 + 통합 테스트 작성","QA 시나리오 작성 및 회귀 테스트 수행"],"excluded":["신규 모바일 네이티브 앱 개발","데이터 마이그레이션 (별도 견적)","오프라인 마케팅 / 영업 지원"],"memo":"프로젝트 기간 12개월 내 프롭테크 도메인 핵심 기능 구현에 집중합니다. 범위 외 요청은 별도 견적으로 진행됩니다."}' WHERE project_id = 1206 AND module_key = 'scope';
