UPDATE project_modules SET data = '{"included":["고객 CS 통합 콘솔 #045 핵심 기능 설계 및 구현","React 18 SPA, Go 1.22 (Gin), Swift (iOS Native), Flutter 3.x 기반 백엔드/프론트 개발","핀테크 도메인 비즈니스 로직 구현","REST API 또는 GraphQL 인터페이스 제공","유닛 테스트 + 통합 테스트 작성","UI/UX 디자인 가이드 적용","CI/CD 파이프라인 구축 및 운영 배포"],"excluded":["운영 인프라 구축 (클라이언트 환경 활용)","신규 모바일 네이티브 앱 개발","오프라인 마케팅 / 영업 지원"],"memo":"프로젝트 기간 3개월 내 핀테크 도메인 핵심 기능 구현에 집중합니다. 범위 외 요청은 별도 견적으로 진행됩니다."}' WHERE project_id = 1215 AND module_key = 'scope';
