UPDATE project_modules SET data = '{"intro":"프로젝트의 원활한 진행과 상호 권리 보호를 위해 아래의 추가 특약 사항을 협의합니다.","terms":[{"id":"nda","icon":"🛡","title":"보안 및 기밀 유지 (NDA)","enabled":true,"items":["프로젝트 관련 모든 자료 및 산출물의 제3자 유출 금지","위반 시 발생한 실손해에 대한 배상 책임"]},{"id":"ip","icon":"©","title":"지식재산권 귀속","enabled":true,"items":["최종 대금 지급 완료 시 산출물 저작권은 클라이언트에게 귀속","작업자의 비상업적 포트폴리오 활용 권한 인정"]},{"id":"warranty","icon":"🔧","title":"유지보수 (3개월 무상)","enabled":true,"items":["배포 후 3개월간 명백한 버그 무상 수정","이후 별도 유지보수 계약 가능"]},{"id":"comm","icon":"💬","title":"커뮤니케이션","enabled":true,"items":["주 1회 정기 미팅 (온라인)","DevBridge 채팅으로 일상 소통"]}]}' WHERE project_id = 1221 AND module_key = 'terms';
UPDATE project_modules SET data = '{"included":["프롭테크 매물 추천 엔진 #052 핵심 기능 설계 및 구현","Django 5, Spring Boot 3.x, EKS / GKE, Next.js 14 (App Router) 기반 백엔드/프론트 개발","공공/B2G 도메인 비즈니스 로직 구현","REST API 또는 GraphQL 인터페이스 제공","유닛 테스트 + 통합 테스트 작성"],"excluded":["데이터 마이그레이션 (별도 견적)","외부 시스템 (CRM/ERP) 추가 연동","운영 인프라 구축 (클라이언트 환경 활용)"],"memo":"프로젝트 기간 11개월 내 공공/B2G 도메인 핵심 기능 구현에 집중합니다. 범위 외 요청은 별도 견적으로 진행됩니다."}' WHERE project_id = 1222 AND module_key = 'scope';
