UPDATE project_modules SET data = '{"included":["B2C 영상 스트리밍 앱 #074 핵심 기능 설계 및 구현","TensorFlow 2.x, Apache Kafka 기반 백엔드/프론트 개발","커머스 도메인 비즈니스 로직 구현","REST API 또는 GraphQL 인터페이스 제공","유닛 테스트 + 통합 테스트 작성","UI/UX 디자인 가이드 적용","CI/CD 파이프라인 구축 및 운영 배포"],"excluded":["신규 모바일 네이티브 앱 개발","다국어 / 글로벌 결제 모듈","데이터 마이그레이션 (별도 견적)"],"memo":"프로젝트 기간 7개월 내 커머스 도메인 핵심 기능 구현에 집중합니다. 범위 외 요청은 별도 견적으로 진행됩니다."}' WHERE project_id = 1244 AND module_key = 'scope';
