UPDATE project_modules SET data = '{"steps":[{"n":1,"title":"결과물 제출","desc":"마일스톤 완료 후 작업자가 결과물을 시스템에 업로드"},{"n":2,"title":"상호 검수 및 수정","desc":"의뢰자 피드백에 따른 오류 수정 및 보완"},{"n":3,"title":"최종 승인 확정","desc":"모든 조건 충족 시 의뢰자가 최종 완료 버튼 클릭"}],"criteria":["온라인 쇼핑몰 풀 리뉴얼 #089 핵심 기능 정상 동작","QA 시나리오 통과율 95% 이상","운영 환경 무중단 배포 검증","주요 브라우저 (Chrome / Safari) 호환성 확보"],"categories":[{"n":1,"title":"API 명세서 전달","desc":"Swagger 기반 모든 핵심/부가 API 명세서 전달 완료"},{"n":2,"title":"기획/UI/UX 정밀 검수","desc":"PRD + UI/UX 디자인 최종안 전달 완료"},{"n":3,"title":"소스코드 리포지토리 전달","desc":"GitHub Private Repo 의 모든 코드 + 배포 스크립트 푸시 완료"},{"n":4,"title":"운영 환경 테스트 완료","desc":"QA 시나리오 + 베타 테스터 결과 보고서 제출 + 버그 수정 완료"}]}' WHERE project_id = 1259 AND module_key = 'completion';
UPDATE project_modules SET data = '{"intro":"프로젝트의 원활한 진행과 상호 권리 보호를 위해 아래의 추가 특약 사항을 협의합니다.","terms":[{"id":"nda","icon":"🛡","title":"보안 및 기밀 유지 (NDA)","enabled":true,"items":["프로젝트 관련 모든 자료 및 산출물의 제3자 유출 금지","위반 시 발생한 실손해에 대한 배상 책임"]},{"id":"ip","icon":"©","title":"지식재산권 귀속","enabled":true,"items":["최종 대금 지급 완료 시 산출물 저작권은 클라이언트에게 귀속","작업자의 비상업적 포트폴리오 활용 권한 인정"]},{"id":"warranty","icon":"🔧","title":"유지보수 (3개월 무상)","enabled":true,"items":["배포 후 3개월간 명백한 버그 무상 수정","이후 별도 유지보수 계약 가능"]},{"id":"comm","icon":"💬","title":"커뮤니케이션","enabled":true,"items":["주 1회 정기 미팅 (온라인)","DevBridge 채팅으로 일상 소통"]}]}' WHERE project_id = 1259 AND module_key = 'terms';
UPDATE project_modules SET data = '{"included":["의료기록 클라우드 마이그레이션 #090 핵심 기능 설계 및 구현","Node.js 20, Vue 3 + Pinia 기반 백엔드/프론트 개발","모바일 도메인 비즈니스 로직 구현","REST API 또는 GraphQL 인터페이스 제공","유닛 테스트 + 통합 테스트 작성","UI/UX 디자인 가이드 적용","CI/CD 파이프라인 구축 및 운영 배포"],"excluded":["데이터 마이그레이션 (별도 견적)","신규 모바일 네이티브 앱 개발","외부 시스템 (CRM/ERP) 추가 연동"],"memo":"프로젝트 기간 8개월 내 모바일 도메인 핵심 기능 구현에 집중합니다. 범위 외 요청은 별도 견적으로 진행됩니다."}' WHERE project_id = 1260 AND module_key = 'scope';
UPDATE project_modules SET data = '{"deliverables":[{"icon":"💻","label":"GitHub 소스코드 (Private Repo)"},{"icon":"🌐","label":"배포된 운영/스테이징 URL"},{"icon":"📘","label":"API 명세서 (Swagger / OpenAPI)"},{"icon":"📊","label":"ERD 및 시스템 아키텍처 다이어그램"},{"icon":"📖","label":"운영 매뉴얼 + 관리자 가이드"},{"icon":"🎬","label":"기능 시연 영상"}],"formats":["GitHub URL","Swagger JSON","PDF",".drawio / .png","MP4"],"delivery":["GitHub Private Repo Invite","DevBridge 채팅 첨부","최종 산출물 ZIP 별도 전달"],"notes":["주요 기술 스택: Node.js 20, Vue 3 + Pinia","운영 환경 배포는 클라이언트 승인 후 진행"]}' WHERE project_id = 1260 AND module_key = 'deliverable';
